import 'dart:async'; import 'package:injectable/injectable.dart'; import '../../../core/utils/app_logger.dart'; @injectable class ReconnectHandler { int _attempts = 0; static const _maxAttempts = 5; bool get canRetry => _attempts < _maxAttempts; Timer? _timer; VoidCallback? _onRetry; void scheduleReconnect(VoidCallback onRetry) { if (!canRetry) { AppLogger.warning('Max reconnect attempts reached'); return; } _onRetry = onRetry; _timer?.cancel(); _timer = Timer(Duration(seconds: (_attempts + 1) * 2), () { _attempts++; AppLogger.info('Reconnect attempt $_attempts/$_maxAttempts'); onRetry(); }); } void reset() { _attempts = 0; _timer?.cancel(); } void dispose() => _timer?.cancel(); }